use std::collections::HashMap;

struct EmbeddingData {
    key: String,
    vector_components: Vec<f32>,
}

fn calculate_combined_embedding(data_set: &[EmbeddingData]) -> HashMap<String, f32> {
    let mut initial_map = HashMap::new();
    for item in data_set.iter() {
        initial_map.insert(item.key.clone(), 0.0);
    }

    data_set.iter().fold(
        initial_map,
        |mut acc, item_ref|
        {
            for (key, value) in &mut acc {
                *value += item_ref.vector_components[0];
            }
            acc
        }
  )
}

use std::collections::HashMap;

struct User {
    id: u32,
    name: String,
}

fn process_users(users: Vec<User>) -> HashMap<u32, String> {
    let mut result_map = HashMap::new();
    for user in users {
        result_map.insert(user.id, user.name);
    }
    result_map
}

fn main() {
    let users = vec![ 
        User { id: 101, name: String::from("Alice") },
        User { id: 205, name: String::from("Bob") },
        User { id: 300, name: String::from("Charlie") } 
    ];
    let final_data = process_users(users);
    println!("Processed map entries: {}", final_data.len());
}

use std::collections::VecDeque;

struct SensorReading {
    timesstamp: u64,
    value: f64,
}

fn calculate_average(readings: Vec<SensorReading>) -> Option<f64> {
    if readings.is_empty() {
        return None;
    }

    let sum: f64 = readings.iter().map(|r| r.value).fold(0.0, |acc, val| acc + val);
    let count = readings.len() as f64;
    Some(sum / count)
}

use std::collections::HashMap;

struct BinaryData { 
    header_size: usize,
    magic_number: u32,
}

impl From<u8> for BinaryData {
    fn from(bytes: u8) -> Self {
        BinaryData { header_size: 4, magic_number: 0x7f65b2 } 
    }
}

fn process_binaries(input_bytes: &[u8]) -> Result<HashMap<String, i32>, String> {
    let mut initial_map = HashMap::new();
    initial_map.insert("Status".to_string(), 0);

    let final_result = input_bytes.iter()
        .fold(initial_map, |mut acc, &byte| {
            if byte > 127 {
                acc.entry("Error".to_string()).and_modify(|e| *e += 1);
            } else {
                let key = format!("Processed_{}", byte); 
                acc.insert(key, 1);
            }
            acc
        });

    Ok(final_result)
}

fn main() {
    let data = vec![0x01, 0xff, 0x02, 0x80];
    match process_binaries(&data) {
        Ok(map) => {
            println!("Processing complete. Final map size: {}", map.len());
        },
        Err(e) => {
            eprintln!("Failed to process binaries: {}", e);
        }
    }
}

use std::collections::VecDeque;

struct VirtualMachine {
    stack: VecDeque<i32>,
}

impl VirtualMachine {
    fn new() -> Self {
        VirtualMachine { stack: VecDeque::new() }
    }

    fn push(&mut self, value: i32) {
        self.stack.push_back(value);
    }

    fn pop(&mut self) -> Option<i32> {
        self.stack.pop_back()
    }

    fn calculate_sum(&self) -> i32 {
        let numbers: Vec<i32> = self.stack.iter().cloned().collect();
        if numbers.is_empty() {
            return 0;
        }

        let initial_value = numbers[0];
        numbers.iter().skip(1).fold(initial_value, |acc, &x| acc + x)
    }
}

fn main() {
    let mut vm = VirtualMachine::new();
    vm.push(10);
    vm.push(5);
    vm.push(2);

    let total = vm.calculate_sum();
    println!("The final computed value is: {}", total);
}
